import os
import sys

sys.path.insert(0, os.path.dirname(__file__))
from _allow_hook_harness import (
    run_hook, cleanup, fresh_ids, legacy_path, sentinel_path,
    suffixed_sentinel_path, seed_legacy, seed_sentinel, stderr_has_usage_error,
)

AC_UID = "c53685918e8ebd62"
AC_TYPE = "hook"


def test_AC15():
    r"""
    GIVEN: pre-existing broad grant files exist for this SID/TASK_ID across ALL
           channels the consumer's sentinel loader reads (codex finding 6 —
           hooks/lib/allowlist.py _enumerate_sentinel_grant_files at :357-370
           globs both '<task_id>.json' AND '<task_id>-*.json'):
             - legacy flag      /tmp/claude-bash-allowlist-<sid>.json
             - canonical sentinel /tmp/claude-grants/<task_id>.json
             - >=1 suffixed sentinel /tmp/claude-grants/<task_id>-<suffix>.json
    WHEN:  a REFUSED /allow runs in the same session (e.g. /allow followed by
           CJK-only prose, or /allow re:.*)
    THEN:  after the refused invocation EVERY pre-existing grant file the
           consumer would honor is removed:
             - preexisting_legacy_removed == True
             - preexisting_sentinel_removed == True
             - preexisting_suffixed_sentinels_removed == True
             - cleanup covers /tmp/claude-grants/${TASK_ID}.json AND
               /tmp/claude-grants/${TASK_ID}-*.json
           so NO stale broad grant of any form survives an invalid /allow. The
           cleanup MUST happen BEFORE exit and BEFORE any new write. A usage
           error is printed; exit 0.

    Observable-behavior contract:
      - seed all three channels (legacy flag, canonical sentinel, suffixed
        sentinel) with broad grants
      - drive the hook with a refused /allow (main agent)
      - assert all three are gone afterward; stderr contains usage error; exit 0
    """
    sid, task_id = fresh_ids()
    lpath = legacy_path(sid)
    spath = sentinel_path(task_id)
    suffixed = suffixed_sentinel_path(task_id, "nonce1")
    try:
        # Seed broad grants across EVERY channel the consumer's loader reads.
        seed_legacy(lpath, ".*", True)
        seed_sentinel(spath, task_id, sid, [{"op": "*", "regex": ".*"}])
        seed_sentinel(suffixed, task_id, sid, [{"op": "*", "regex": ".*"}])
        assert os.path.exists(lpath) and os.path.exists(spath) and os.path.exists(suffixed)

        # A REFUSED /allow in the same session must wipe every stale grant.
        r = run_hook("/allow re:.*", sid, task_id)
        assert r["exit"] == 0, f"expected exit 0, got {r['exit']}"
        assert stderr_has_usage_error(r["stderr"]), f"usage error expected; stderr={r['stderr']!r}"
        assert not os.path.exists(lpath), "stale legacy flag must be removed"
        assert not os.path.exists(spath), "stale canonical sentinel must be removed"
        assert not os.path.exists(suffixed), "stale suffixed <task_id>-*.json sentinel must be removed"
    finally:
        cleanup(sid, task_id)
